+        let mut parser = InputParser::new();
+
+        // Start paste mode
+        parser.parse(b"\x1b[200~");
+
+        // Overflow the buffer by pushing more than MAX_PASTE_LEN bytes.
+        // DoS protection truncates to 64 bytes once the limit is exceeded,
