+    fn new() -> io::Result<Self> {
+        let mut signals = Signals::new([SIGINT, SIGTERM, SIGWINCH]).map_err(io::Error::other)?;
+        let handle = signals.handle();
+        let thread = std::thread::spawn(move || {
