+        minimum: 0,
+        maximum: 0,
+    };
+
+    /// Union: take max of both bounds (side-by-side layout).
+    pub fn union(self, other: Self) -> Self {
+        Self {
+            minimum: self.minimum.max(other.minimum),
+            maximum: self.maximum.max(other.maximum),
+        }
+    }
